SET client_encoding TO 'UTF8';

SET check_function_bodies = false;





CREATE OR REPLACE FUNCTION f_get_number_to_words ( adc_number bigint) RETURNS varchar AS $body$
DECLARE

    ldc_number bigint := adc_number;
    ldc_return varchar(2000);
    ldc_power bigint;
    ldc_chunk bigint;

    -- อาร์เรย์สำหรับเลข 0-19
    TYPE small_numbers IS TABLE OF varchar(20) INDEX BY integer;
    ldc_small small_numbers;

    -- อาร์เรย์สำหรับสิบ (20, 30, ... 90)
    TYPE tens_numbers IS TABLE OF varchar(20) INDEX BY integer;
    ldc_tens tens_numbers;

    -- อาร์เรย์สำหรับหน่วย (พัน, ล้าน, etc.)
    TYPE scale_numbers IS TABLE OF varchar(20) INDEX BY integer;
    ldc_scale scale_numbers;

    FUNCTION convert_less_than_one_thousand(ldc_p_num IN bigint) RETURN text IS
        ldc_num bigint := ldc_p_num;
        ls_result varchar(200);

BEGIN
        IF ldc_num = 0 THEN
            RETURN NULL;
        END IF;

        -- แปลงหลักร้อย
        IF ldc_num >= 100 THEN
            ls_result := ldc_small(date_trunc('day', ldc_num / 100)) || ' hundred';
            ldc_num := MOD(ldc_num, 100);

            IF ldc_num > 0 THEN
                ls_result := ls_result || ' and ';
            END IF;
        END IF;

        -- แปลงหลักสิบและหน่วย
        IF ldc_num >= 20 THEN
            ls_result := ls_result || ldc_tens(date_trunc('day', ldc_num / 10));
            ldc_num := MOD(ldc_num, 10);

            IF ldc_num > 0 THEN
                ls_result := ls_result || '-';
            END IF;
        END IF;

        IF ldc_num > 0 AND ldc_num < 20 THEN
            ls_result := ls_result || ldc_small(ldc_num);
        END IF;

        RETURN ls_result;
    END;

BEGIN
    -- ตรวจสอบว่าตัวเลขเป็น 0 หรือไม่
    IF ldc_number = 0 THEN
        RETURN 'zero';
    END IF;

    -- กำหนดค่าอาร์เรย์สำหรับเลขเล็ก
    ldc_small(0) := 'zero';
    ldc_small(1) := 'one';
    ldc_small(2) := 'two';
    ldc_small(3) := 'three';
    ldc_small(4) := 'four';
    ldc_small(5) := 'five';
    ldc_small(6) := 'six';
    ldc_small(7) := 'seven';
    ldc_small(8) := 'eight';
    ldc_small(9) := 'nine';
    ldc_small(10) := 'ten';
    ldc_small(11) := 'eleven';
    ldc_small(12) := 'twelve';
    ldc_small(13) := 'thirteen';
    ldc_small(14) := 'fourteen';
    ldc_small(15) := 'fifteen';
    ldc_small(16) := 'sixteen';
    ldc_small(17) := 'seventeen';
    ldc_small(18) := 'eighteen';
    ldc_small(19) := 'nineteen';

    -- กำหนดค่าอาร์เรย์สำหรับสิบ
    ldc_tens(2) := 'twenty';
    ldc_tens(3) := 'thirty';
    ldc_tens(4) := 'forty';
    ldc_tens(5) := 'fifty';
    ldc_tens(6) := 'sixty';
    ldc_tens(7) := 'seventy';
    ldc_tens(8) := 'eighty';
    ldc_tens(9) := 'ninety';

    -- กำหนดค่าอาร์เรย์สำหรับหน่วยใหญ่
    ldc_scale(0) := '';
    ldc_scale(1) := ' thousand';
    ldc_scale(2) := ' million';
    ldc_scale(3) := ' billion';
    ldc_scale(4) := ' trillion';

    -- เริ่มต้นการแปลง
    ldc_return := NULL;

    -- แปลงตัวเลขทีละ 3 หลัก
    FOR i IN REVERSE 4..0 LOOP
        ldc_power := POWER(1000, i);
        ldc_chunk := date_trunc('day', ldc_number / ldc_power);

        IF ldc_chunk > 0 THEN
            IF (ldc_return IS NOT NULL AND ldc_return::text <> '') THEN
                ldc_return := ldc_return || ', ';
            END IF;

            ldc_return := ldc_return || convert_less_than_one_thousand(ldc_chunk) || ldc_scale(i);
            ldc_number := MOD(ldc_number, ldc_power);
        END IF;
    END LOOP;

    -- จัดการกรณีมีเศษสตางค์ (ถ้าต้องการ)
    -- IF ldc_number > 0 THEN
    --     ldc_return := ldc_return || ' and ' || convert_less_than_one_thousand(ldc_number);
    -- END IF;
    RETURN ldc_return;
EXCEPTION
    WHEN OTHERS THEN
        RETURN 'Error converting number to words: ' || SQLERRM;
END;
$body$
LANGUAGE PLPGSQL
SECURITY DEFINER
;
-- REVOKE ALL ON FUNCTION f_get_number_to_words ( adc_number bigint) FROM PUBLIC;

